execute:
(
    {
        "metadata": {
            "_aresId": _aresId,
            "sessionId": sessionId,
            "pagination": pagination,
            "metadata": metadata
        },
        "entries": $append([], $map(blocks.items, function($item, $i) {(
            $sift(
                $merge([$item, {
                    "trackId": "ARES|" & _aresId & "|" & $item._aresId & "|" & ($i + 1)
                }]),
                function($v, $k) {(
                    $v != null 
                    and (
                        $k != "_aresId" 
                        and $k != "_contentType" 
                        and $k != "publication_date"
                        and $k != "horizontal_poster"
                        and $k != "video_content_id"
                        and $k != "people-regista"
                    )
                )}
            );
        )}))
    }
)
